Javascript.validate:
	    	//Date picker: error message “The value does not conform to a valid date format of DD-MMM-YYYY”.
			//Validation: Date cannot be in the past
				
    			var checkDate = Services.getValue(AdjournedDate.dataBinding); 
				var err = null;
				if( false == isFutureDate(checkDate))
				{ 	
					err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInThePast_Msg");
				}				
				return err;
